# Claude Zombies - default map
#
# Format reference (see also src/engine/mapdoc.c):
#
#   NAME <text...>
#   ARENA halfX halfZ                        (optional; default 40 40)
#   ATMOSPHERE ... END                       (fog/sky_tint/music)
#   TEXTURES ... END                         (per-map slot overrides)
#
#   SECTOR <name> x z sx sz y                (flat floor area at height y)
#   RAMP   <name> x z sx sz yLow yHigh X|Z [LINK a b]  (slope/stair, nav edge)
#     ...placed entities (below) live inside a SECTOR/RAMP block and take
#        their floor height from it...
#   END
#
#   SPAWN PLAYER x z                         (player start)
#   SPAWN MOB <mob> x z [LOCKED_BY <door>]   (mob spawn, e.g. ZOMBIE; optional gate)
#   WALL  x1 z1 x2 z2 [DOOR center width cost [AS name]] [TEX name]
#   WINDOW x z <+x|-x|+z|-z> [LOCKED_BY <door_name>]
#   WALLBUY x z <+x|-x|+z|-z> WEAPON         (PISTOL/SMG/SHOTGUN/RIFLE/RAYGUN)
#   PERK    x z PERK                         (JUG/SPEED/DTAP/STAMIN)
#   PAP     x z
#   MBOX    x z
#   OBSTACLE x z sx sz [h]                   (h defaults to 2.0)
#   PROP <name> x z [yaw <deg>] [scale <s>]

NAME Default

ATMOSPHERE
    fog       18 22 35  12 60
    sky_tint  255 255 255
END

SECTOR ground  0 0  80 80  0
    SPAWN PLAYER  0 0
    SPAWN PLAYER  2 0
    SPAWN PLAYER -2 0
    SPAWN PLAYER  0 2

    OBSTACLE  10  5    4 4 3
    OBSTACLE -12 -8    6 3
    OBSTACLE -10 -16   4 4 3
    OBSTACLE  18 -15   3 6
    OBSTACLE -20  12   5 5 3
    OBSTACLE   8  20   7 2
    OBSTACLE  -6  26   3 3 3
    OBSTACLE  25   2   2 8

    WALL -40 -20  40 -20  DOOR 0 2 1500 AS central_door

    WALLBUY  15    39.45  -z  SHOTGUN
    WALLBUY  39.45 -10    -x  SMG
    WALLBUY -15   -39.45  +z  RIFLE
    WALLBUY -39.45 18     +x  RAYGUN

    WINDOW -18   40   -z
    WINDOW  40   18   -x
    WINDOW  18  -40   +z LOCKED_BY central_door
    WINDOW -40   -8   +x

    PERK  -8  12 JUG
    PERK   4  -8 SPEED
    PERK  22  25 DTAP
    PERK -25 -22 STAMIN

    MBOX -22 15
    PAP   0 -28
END
